// Map categories to email template types
export function getTemplateForCategory(category) {
  const sponsorshipCategories = ["auto", "bank", "insurance", "construction", "healthcare", "realestate", "legal", "financial", "manufacturing", "strategic"];
  const inkindCategories = ["restaurant", "brewery", "retail", "golf", "beverage", "food", "national", "auction"];
  const socialCategories = ["media", "advocate"];

  if (sponsorshipCategories.includes(category)) return "cold_email";
  if (inkindCategories.includes(category)) return "inkind_ask";
  if (socialCategories.includes(category)) return "social_post";
  return "cold_email";
}

